output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?mallLabel WHERE {
  wd:Q1473 wdt:P31 wd:Q515 ; wdt:P17 wd:Q162 ; wdt:P1082 ?population .
  ?mall wdt:P31 wd:Q4155622 ; wdt:P131 wd:Q1473 .
  ?mall rdfs:label ?mallLabel .
  FILTER(LANG(?mallLabel) = 'en')
  FILTER NOT EXISTS {
    ?mall wdt:P131 ?otherCity
  }
}

args.sparql:
SELECT ?cityLabel ?population WHERE {
  ?city wdt:P31 wd:Q515 ;
        wdt:P17 wd:Q162 ;
        wdt:P1082 ?population .
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en". }
} ORDER BY DESC(?population) LIMIT 3

SELECT ?cityLabel ?population WHERE {
  ?city wdt:P31 wd:Q515 ;
        wdt:P17 wd:Q162 ;
        wdt:P1082 ?population .
  ?city rdfs:label ?cityLabel .
  FILTER (LANG(?cityLabel) = 'en')
} ORDER BY DESC(?population) LIMIT 3

SELECT ?mallLabel WHERE {
  wd:Q1473 wdt:P131 ?city .
  ?mall wdt:P31 wd:Q4155622 ;
        wdt:P131 wd:Q1473 .
  ?mall rdfs:label ?mallLabel .
  FILTER (LANG(?mallLabel) = 'en')
}

SELECT ?mallLabel WHERE {
  wd:Q1473 wdt:P31 wd:Q515 ;
            wdt:P17 wd:Q162 ;
            wdt:P1082 ?population .
  ?mall wdt:P31 wd:Q4155622 ;
        wdt:P131 wd:Q1473 .
  ?mall rdfs:label ?mallLabel .
  FILTER (LANG(?mallLabel) = 'en')
  FILTER NOT EXISTS { ?mall wdt:P131 ?otherCity }
}
